import (
	context "context"
	fern "github.com/endpoint-security-auth/fern"
	fernclient "github.com/endpoint-security-auth/fern/client"
	option "github.com/endpoint-security-auth/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Auth.Gettoken(
	context.TODO(),
	&fern.AuthGetTokenRequest{
		ClientID:     "client_id",
		ClientSecret: "client_secret",
		Audience:     fern.AuthGetTokenRequestAudienceHttpsApiExampleCom,
		GrantType:    fern.AuthGetTokenRequestGrantTypeClientCredentials,
	},
)

